new_tags = [
  {"id": 400, "keyword_tag": "油", "knowledge_tag": "製作技巧", "explanation": "荷葉包（刈包）在對摺蒸之前，中間一定會刷上一層「油」，這樣蒸熟後兩層麵皮才不會黏在一起，方便剝開夾控肉。"},
  {"id": 401, "keyword_tag": "火燒", "knowledge_tag": "麵糰特性", "explanation": "「火燒」是一種口感非常乾硬的烤餅（例如槓子頭），它的配方含水量極低，所以吃起來非常有咬勁。"},
  {"id": 402, "keyword_tag": "低筋發粉大火", "knowledge_tag": "製作技巧", "explanation": "發糕要開出漂亮的大裂口，秘訣就是：使用沒有拉力的「低筋麵粉」、添加足夠產氣的「發粉（泡打粉）」，以及最重要的「大火」猛烈蒸氣！"},
  {"id": 403, "keyword_tag": "馬拉糕", "knowledge_tag": "產品配方", "explanation": "馬拉糕是一種起源於廣東的發酵蒸蛋糕，配方中除了麵粉和糖，還加了大量的「雞蛋」，所以吃起來特別鬆軟有蛋香。"},
  {"id": 404, "keyword_tag": "燒餅", "knowledge_tag": "熟製方式", "explanation": "雙胞胎、沙琪瑪、開口笑全部都是丟進油鍋裡「炸」出來的。只有「燒餅」是貼在爐壁上或是放進烤箱「烤」出來的。"},
  {"id": 405, "keyword_tag": "沙琪瑪", "knowledge_tag": "膨大機制", "explanation": "沙琪瑪的麵糰是靠雞蛋和泡打粉來發泡，加上高溫油炸瞬間膨脹，完全不需要依賴「酵母菌」發酵。"},
  {"id": 406, "keyword_tag": "煮", "knowledge_tag": "熟製方式", "explanation": "冷水麵（如水餃、麵條、麵疙瘩、餛飩）因為麵筋強韌，最常見也最適合的熟製方式就是丟進滾水裡「煮」。"},
  {"id": 407, "keyword_tag": "手抓餅", "knowledge_tag": "產品分類", "explanation": "手抓餅通常是用溫水或「冷水麵」揉製出麵筋，再靠層層折疊刷油來產生Ｑ彈有嚼勁的口感。"},
  {"id": 408, "keyword_tag": "燙麵>冷水麵", "knowledge_tag": "吸水性", "explanation": "燙麵因為熱水把澱粉糊化了，吸水能力變得超級強，所以配方的含水量絕對是「燙麵 大於 冷水麵」。"},
  {"id": 409, "keyword_tag": "新鮮酵母>速溶酵母", "knowledge_tag": "酵母換算", "explanation": "新鮮酵母含有約 70% 的水分，而速溶酵母幾乎乾燥。所以在配方換算上，新鮮酵母的使用量絕對「大於」速溶乾酵母。"},
  {"id": 410, "keyword_tag": "特高筋麵粉", "knowledge_tag": "麵粉選擇", "explanation": "油條在油鍋中會產生劇烈的氣體膨脹，必須要有超強的麵筋網來包覆氣體才不會破裂，所以最好使用蛋白質含量最高的「特高筋麵粉」。"},
  {"id": 411, "keyword_tag": "饅頭", "knowledge_tag": "水質影響", "explanation": "水質的酸鹼度和礦物質會直接影響「酵母」的活動力。在四個選項中，只有「饅頭」是靠酵母發酵的，所以影響最大。"},
  {"id": 412, "keyword_tag": "溫度高水多酵母多", "knowledge_tag": "發酵機制", "explanation": "要讓酵母發酵速度飆到最快，就是給它最愛的溫暖環境（溫度高）、足夠的水分（水量多），並且增加酵母大軍的數量（酵母量多）。"},
  {"id": 413, "keyword_tag": "小麥澱粉", "knowledge_tag": "原料特性", "explanation": "要做水晶餃或港式蝦餃那種透明Ｑ彈的皮，一定要用洗去麵筋的「小麥澱粉（澄粉）」，燙熟後就會呈現晶瑩剔透的質感。"},
  {"id": 414, "keyword_tag": "碳酸鈉", "knowledge_tag": "化學特性", "explanation": "製作油麵用來增加風味、彈性並防腐的鹼水，其主要的化學成分是「碳酸鈉」（俗稱純鹼或蘇打）。"},
  {"id": 415, "keyword_tag": "燒餅類麵食", "knowledge_tag": "產品分類", "explanation": "蟹殼黃是用油皮包油酥，裡面包著蔥肉餡，表面沾滿芝麻烤出來的鹹點心。在麵食分類上屬於「燒餅類（酥油皮類）」。"},
  {"id": 416, "keyword_tag": "兩相好", "knowledge_tag": "產品配方", "explanation": "兩相好（雙胞胎）是一種台式傳統點心，它的麵糰必須加入「酵母」和發粉雙重發酵，炸出來才會外酥內軟。"},
  {"id": 417, "keyword_tag": "發麵燒餅", "knowledge_tag": "產品分類", "explanation": "「發麵燒餅」是用加了酵母的發酵麵糰做的（像厚厚的麵包），裡面沒有油皮包油酥的層次結構。"},
  {"id": 418, "keyword_tag": "雞蛋麵條", "knowledge_tag": "原料應用", "explanation": "雞蛋麵條是靠雞蛋的蛋白質來增加彈性，不需要也不會使用「鹼水」，否則會破壞雞蛋的風味。"},
  {"id": 419, "keyword_tag": "水煎包", "knowledge_tag": "熟製方式", "explanation": "牛肉餡餅是在平底鍋裡加一點油，慢慢把兩面「煎」熟。這跟水煎包底部用油煎脆的原理最相似。"},
  {"id": 420, "keyword_tag": "油量大於糖量大於蛋量", "knowledge_tag": "配方比例", "explanation": "鳳梨酥外皮要非常酥鬆、入口即化，秘訣就是「油的比例要最高」，其次是糖，最後才是負責黏合的蛋（油>糖>蛋）。"},
  {"id": 421, "keyword_tag": "方塊酥", "knowledge_tag": "油脂應用", "explanation": "方塊酥是一層一層的酥皮餅乾，必須使用在常溫下不會融化的「固態油脂（如豬油、白油）」，烤出來層次才會分明。"},
  {"id": 422, "keyword_tag": "上火小下火大", "knowledge_tag": "烤焙技巧", "explanation": "綠豆椪這種白色台式月餅，表面要求雪白不焦，但底部又必須烤酥熟透，所以一定要設定成「上火小、下火大」。"},
  {"id": 423, "keyword_tag": "放冷後包裝", "knowledge_tag": "包裝技巧", "explanation": "蘿蔔絲酥餅剛出爐很燙，如果立刻包裝，熱氣會在袋子裡凝結成水珠，把酥脆的外皮弄濕軟掉，所以一定要「放冷後」才能包裝。"},
  {"id": 424, "keyword_tag": "增進產品風味", "knowledge_tag": "包裝目的", "explanation": "包裝可以保護產品、延長保存、變漂亮好賣，但包裝袋本身沒有味道，不可能讓食物吃起來變好吃（增進風味）。"},
  {"id": 425, "keyword_tag": "負20℃", "knowledge_tag": "包裝材質", "explanation": "冷凍水餃通常要存放在 -18℃ 以下的冷凍庫裡，所以包裝袋的材質至少必須能承受「-20℃」的低溫而不破裂。"},
  {"id": 426, "keyword_tag": "玻璃容器", "knowledge_tag": "包裝材質", "explanation": "玻璃雖然漂亮，但太重、容易打破、成本高，而且無法阻擋光線。所以市面上幾乎沒有人用「玻璃容器」來包裝月餅。"},
  {"id": 427, "keyword_tag": "食用量", "knowledge_tag": "包裝標示", "explanation": "食品法規規定外包裝必須標示品名、成分、廠商、有效期限等資訊。至於消費者一次要吃多少（食用量），並沒有強制規定。"},
  {"id": 428, "keyword_tag": "透光性", "knowledge_tag": "包裝機能", "explanation": "光線中的紫外線會讓食物裡的油脂加速氧化變質。所以多數食品包裝反而要求避光，最不需要的機能就是「透光性」。"},
  {"id": 429, "keyword_tag": "回收", "knowledge_tag": "食品安全", "explanation": "只要是超過保存期限的食品，不論包裝有沒有壞，依法規定一律只能做「回收」銷毀處理，絕對不能換包裝再賣。"},
  {"id": 430, "keyword_tag": "鋁箔", "knowledge_tag": "加熱常識", "explanation": "微波爐是利用電磁波加熱，金屬材質（如「鋁箔」、不鏽鋼）會反射微波並產生火花，非常危險，絕對不可放進微波爐！"},
  {"id": 431, "keyword_tag": "體積", "knowledge_tag": "包裝影響", "explanation": "如果包裝破洞漏氣，食物會氧化變色、吸濕變軟、風味流失。但產品原本烤出來有多大（體積），不會因為包裝沒包好就縮水。"},
  {"id": 432, "keyword_tag": "玻璃紙", "knowledge_tag": "包裝材質", "explanation": "「玻璃紙」是用木漿做成的再生纖維素，它像紙一樣，遇熱不會像塑膠那樣收縮融化，所以不具備熱收縮性。"},
  {"id": 433, "keyword_tag": "牛皮紙袋", "knowledge_tag": "包裝材質", "explanation": "粉狀麵粉如果不油、水分也低，最環保又便宜的包裝材料就是用紙漿做的「牛皮紙袋」，透氣又好回收。"},
  {"id": 434, "keyword_tag": "療效", "knowledge_tag": "食品法規", "explanation": "食品衛生管理法嚴格規定，一般食品（包括中式麵食）的廣告或包裝標示，絕對不可以使用宣稱醫療「療效」的字眼。"},
  {"id": 435, "keyword_tag": "不得檢出", "knowledge_tag": "食品安全", "explanation": "甲醛（福馬林）是劇毒致癌物，食品接觸的塑膠包材法規標準非常嚴格，規定是「不得檢出（也就是 0 容忍）」。"},
  {"id": 436, "keyword_tag": "使麵食更可口", "knowledge_tag": "包裝目的", "explanation": "包裝的主要功能是保護產品不受蟲害或細菌污染、延長壽命。包裝只能讓食物看起來賣相好，但無法改變食物本身的味道讓它「更可口」。"},
  {"id": 437, "keyword_tag": "玻璃紙", "knowledge_tag": "包裝材質", "explanation": "玻璃紙（Cellophane）的結構非常緊密，孔隙極小，具有極佳的防油性（不易滲油），常被用來墊在糕點底部。"},
  {"id": 438, "keyword_tag": "金屬", "knowledge_tag": "包裝材質", "explanation": "在所有常見的食品包裝材料（紙、塑膠、玻璃、金屬）中，開模製作「金屬（鐵盒、鋁罐）」的成本是最高的。"},
  {"id": 439, "keyword_tag": "鋁箔", "knowledge_tag": "包裝材質", "explanation": "「鋁箔」是金屬薄膜，完全不透光也不透氣，是所有軟性包裝材料中阻隔性與「遮光性」最好的一種。"},
  {"id": 440, "keyword_tag": "聚乙烯", "knowledge_tag": "包裝材質", "explanation": "PE（聚乙烯）的熔點較低，只要稍微加熱就會融化黏合，所以是所有塑膠材質中「熱封性」最好、最常被拿來做封口層的材料。"},
  {"id": 441, "keyword_tag": "聚丙烯聚乙烯", "knowledge_tag": "包裝材質", "explanation": "水氣高又要冷凍冷藏的食品（如水餃、包子），最適合使用複合式的防潮塑膠膜「OPP/CPP 或 PE」，便宜耐低溫又防水。"},
  {"id": 442, "keyword_tag": "聚乙烯", "knowledge_tag": "包裝材質", "explanation": "PE（聚乙烯）雖然容易熱封，但它的表面張力很低，油墨很難附著在上面，所以「很難直接印刷」，通常要與其他材料複合。"},
  {"id": 443, "keyword_tag": "順式脂肪酸", "knowledge_tag": "食品法規", "explanation": "營養標示必須列出對健康有疑慮的飽和脂肪與反式脂肪。但天然無害的「順式脂肪酸」則不在強制標示的範圍內。"},
  {"id": 444, "keyword_tag": "螢光增白劑", "knowledge_tag": "食品安全", "explanation": "「螢光增白劑」是一種化學染料，接觸到食物被吃下肚會危害健康，因此法規明令接觸食品的包材或紙張「不得檢出」。"},
  {"id": 445, "keyword_tag": "透光性", "knowledge_tag": "包裝設計", "explanation": "設計包裝時要考慮方便性、美觀（商品性）和成本（經濟性）。至於「透光性」通常是為了保護產品避光，不是外觀設計首要考量。"},
  {"id": 446, "keyword_tag": "透光度", "knowledge_tag": "包裝機能", "explanation": "麵食包材最重要的是熱封牢不牢、耐不耐熱或耐不耐凍。至於「透光度」對已經熟製的麵食保存影響相對較小，是最不需要優先考慮的。"},
  {"id": 447, "keyword_tag": "鍍鋁聚酯膜", "knowledge_tag": "包裝材質", "explanation": "怕光的食物（例如容易氧化的油炸麵食），可以使用「鍍鋁聚酯膜（VMPET）」，它在塑膠膜上鍍了一層金屬鋁，遮光效果極佳。"},
  {"id": 448, "keyword_tag": "紙盒", "knowledge_tag": "包裝材質", "explanation": "為了響應環保、減少塑膠和金屬垃圾，現在月餅的禮盒外包裝最推薦選用可以回收分解的「紙盒」。"},
  {"id": 449, "keyword_tag": "複合聚酯", "knowledge_tag": "包裝材質", "explanation": "冷凍水餃在冷凍庫會碰撞，需要極強的抗刺穿性，所以包裝袋大多採用 PET/PE/LLDPE 黏在一起的「複合塑膠膜」。"},
  {"id": 450, "keyword_tag": "塑膠製品", "knowledge_tag": "包裝材質", "explanation": "冷凍水餃會產生水氣，不能用紙盒；鋁箔太貴也看不見內容物。所以防水又耐凍的「塑膠製品（複合膜）」是最適合的材質。"},
  {"id": 451, "keyword_tag": "KOP/CPP", "knowledge_tag": "包裝材質", "explanation": "蛋黃酥很怕吸濕軟掉，也怕裡面的酥油氧化有油耗味。使用表面塗佈了防氧塗層的「KOP/CPP」複合膜，防潮防氧效果最好。"},
  {"id": 452, "keyword_tag": "廠商", "knowledge_tag": "食品法規", "explanation": "依據食品安全衛生管理法，包裝食品必須明確標示負責製造或進口的「廠商」名稱、地址與電話，以示負責。"},
  {"id": 453, "keyword_tag": "聚苯乙烯", "knowledge_tag": "包裝材質", "explanation": "蛋黃酥紙盒裡面裝著一顆顆月餅的透明或白色凹槽塑膠底座，通常是使用容易真空成型、質地較硬的「PS（聚苯乙烯）」做的。"},
  {"id": 454, "keyword_tag": "食品營養", "knowledge_tag": "包裝安全", "explanation": "包裝安全是指包裝材料不能有毒（食品衛生），包裝技術要能防菌防蟲。至於產品裡面蛋白質、維生素有多少（食品營養），跟包裝安不安全無關。"},
  {"id": 455, "keyword_tag": "塑膠製品", "knowledge_tag": "環保觀念", "explanation": "一般塑膠製品在自然界中幾百年都無法分解，燃燒還會產生有毒氣體。為了地球環保，最好盡量減少使用「塑膠製品」。"},
  {"id": 456, "keyword_tag": "透氣性", "knowledge_tag": "包裝機能", "explanation": "冷凍麵食在低溫下已經停止發酵和呼吸，最怕的反而是水氣散失造成表面乾裂，所以包裝必須密封，完全不需要考慮「透氣性」。"},
  {"id": 457, "keyword_tag": "脫氧劑", "knowledge_tag": "食品保存", "explanation": "廣式月餅裡面有很多油脂和水分，為了防止發霉和油脂氧化有油耗味，包裝內通常會放一包「脫氧劑」把氧氣吸光。"},
  {"id": 458, "keyword_tag": "黑糖來源", "knowledge_tag": "標示法規", "explanation": "包裝標示必須寫上品名、成分和期限。法規只要求你寫成分有「黑糖」，並沒有規定你要交代黑糖是跟哪一家工廠買的（黑糖的來源）。"},
  {"id": 459, "keyword_tag": "水", "knowledge_tag": "麵糰特性", "explanation": "在攪拌冷水麵時，麵粉吸附水分會變得柔軟。所以「水」加得越多，麵糰當然就越濕、越柔軟。"},
  {"id": 460, "keyword_tag": "顏色變白", "knowledge_tag": "異常分析", "explanation": "麵糰如果發酵過度（發太久），酵母吃光了糖分，而且產生大量酸性物質，蒸出來的麵食顏色會變得暗淡偏黃，絕對不會「顏色變白」。"},
  {"id": 461, "keyword_tag": "蒸", "knowledge_tag": "熟製方式", "explanation": "酥油皮（如蛋黃酥）就是要烤出層層酥脆感。如果用「蒸」的，水氣會把酥皮完全泡軟爛成一團麵糊，非常不適合。"},
  {"id": 462, "keyword_tag": "外脆內軟", "knowledge_tag": "品質鑑定", "explanation": "煎得完美的蔥油餅，外皮接觸油鍋被煎得金黃酥「脆」，但內部因為層層包油保留了水分，吃起來必須是Ｑ「軟」的。"},
  {"id": 463, "keyword_tag": "炸", "knowledge_tag": "熟製方式", "explanation": "雖然銀絲捲是用蒸的做出來，但在餐廳裡最受歡迎、最理想的吃法，是下鍋油「炸」到外皮金黃酥脆，然後沾煉乳吃。"},
  {"id": 464, "keyword_tag": "有油耗味", "knowledge_tag": "品質鑑定", "explanation": "水餃如果有「油耗味」，代表肉餡裡的脂肪已經氧化不新鮮，或者加的香油壞掉了，這絕對是最不受歡迎的糟糕品質。"},
  {"id": 465, "keyword_tag": "油炸溫度與時間", "knowledge_tag": "製作技巧", "explanation": "沙琪瑪的麵條含有蛋和泡打粉，必須依靠「適當的高溫和時間」瞬間下鍋油炸，麵條才會立刻膨脹並且變得酥脆。"},
  {"id": 466, "keyword_tag": "強韌", "knowledge_tag": "麵糰特性", "explanation": "冷水麵裡的麵筋結構完整，沒有被熱水燙熟破壞，所以吃起來的口感會比燙麵麵食還要Ｑ彈「強韌」。"},
  {"id": 467, "keyword_tag": "氣孔粗大", "knowledge_tag": "品質鑑定", "explanation": "做工精良的饅頭，切開來內部組織應該是細緻均勻的。如果出現「氣孔粗大」，代表壓麵沒壓好或是發酵過頭了。"},
  {"id": 468, "keyword_tag": "湯汁混濁", "knowledge_tag": "品質鑑定", "explanation": "品質好的乾麵條表面結實，丟進滾水裡煮的時候，澱粉不會大量脫落。如果「水煮時湯汁混濁（糊湯）」，代表麵條品質不良。"},
  {"id": 469, "keyword_tag": "足夠的火力", "knowledge_tag": "製作技巧", "explanation": "發糕要漂亮龜裂（開花），除了發粉量要對，最關鍵的就是蒸籠必須保持「足夠的猛烈火力」讓麵糊瞬間往上衝發爆開。"},
  {"id": 470, "keyword_tag": "澄粉", "knowledge_tag": "異常分析", "explanation": "澄粉（小麥澱粉）熟了會變成黏黏透明的糊狀。如果叉燒包配方裡加了太多澄粉，吃的時候澱粉糊就會死死黏在牙齒上。"},
  {"id": 471, "keyword_tag": "比例適當", "knowledge_tag": "品質鑑定", "explanation": "油酥和油皮就像千層派的千層一樣，只有兩者的軟硬度、厚薄度與「比例適當（通常是皮2：酥1）」，烤出來才會層次分明。"},
  {"id": 472, "keyword_tag": "油炸溫度與時間", "knowledge_tag": "製作技巧", "explanation": "巧果麵片很薄，必須靠「適當的油炸溫度與時間」，讓它瞬間把水氣炸乾又不會焦掉，吃起來才會脆卡卡。"},
  {"id": 473, "keyword_tag": "烤至表面凝結", "knowledge_tag": "製作技巧", "explanation": "生鹹蛋黃腥味重且水份多，包入月餅前通常會噴點酒，放進烤箱「烤至表面凝結（微出油）」去腥，但不能烤到全熟破裂。"},
  {"id": 474, "keyword_tag": "層次多", "knowledge_tag": "製作技術", "explanation": "「小包酥」是一顆一顆油皮包一顆顆油酥，再個別手工兩次桿捲。這種做法雖然費工，但做出來的酥皮「層次多」又細緻分明。"},
  {"id": 475, "keyword_tag": "柔軟", "knowledge_tag": "麵糰特性", "explanation": "燙麵的熱水會破壞大部分麵筋並使澱粉糊化，糊化的澱粉保水性好，所以放冷之後，吃起來還是比冷水麵「柔軟」。"},
  {"id": 476, "keyword_tag": "由外觀看出", "knowledge_tag": "品質鑑定", "explanation": "菊花酥、蓮花酥這類叫做「明酥」的產品，最大特色就是必須在切刀和捏塑的過程中，讓美麗的酥皮層次直接「可由外觀看出」。"},
  {"id": 477, "keyword_tag": "煮", "knowledge_tag": "加熱常識", "explanation": "菜肉包本來就是蒸的發酵麵食，麵皮有毛細孔。如果把它丟進水裡「煮」，麵皮會立刻吸滿水分變成一團爛泥。"},
  {"id": 478, "keyword_tag": "脆", "knowledge_tag": "品質鑑定", "explanation": "水煎包最迷人的地方，就是除了麵皮有包子的鬆軟外，底部還因為接觸熱油鍋，煎出一層金黃酥「脆」的冰花鍋巴。"},
  {"id": 479, "keyword_tag": "焦黑", "knowledge_tag": "品質鑑定", "explanation": "菊花酥外型像花朵，顏色應該是烤得金黃誘人。如果火候沒控制好烤到「焦黑」，不只難看而且會有苦味，是最不受歡迎的。"},
  {"id": 480, "keyword_tag": "乾硬", "knowledge_tag": "品質鑑定", "explanation": "冷水麵麵筋很強，水分也不多，如果不加水用乾煎或烙烤的方式，水分蒸發後麵筋會緊縮，成品就會變得非常「乾硬」有咬勁。"},
  {"id": 481, "keyword_tag": "酥鬆", "knowledge_tag": "品質鑑定", "explanation": "一顆完美的鳳梨酥，外皮咬下去必須是沒有阻力、入口即化的「酥鬆」口感，絕對不能像石頭一樣堅硬或有咬勁。"},
  {"id": 482, "keyword_tag": "外軟內酥", "knowledge_tag": "品質鑑定", "explanation": "好吃的燒餅表面沾滿芝麻，必須烤到「外皮酥脆、內部軟Ｑ」。如果是「外軟內酥」，代表受潮軟掉了，是不合格的品質。"},
  {"id": 483, "keyword_tag": "炸或烤", "knowledge_tag": "熟製方式", "explanation": "蘿蔔絲酥餅屬於酥油皮麵食，必須利用高溫的熱油「炸」或烤箱「烤」，才能把麵糰裡的油脂逼出來，形成層層酥鬆的結構。"},
  {"id": 484, "keyword_tag": "奶粉", "knowledge_tag": "配方分析", "explanation": "饅頭組織會柔軟，靠的是酵母產氣、水分濕潤、油脂滋潤。加「奶粉」只是為了增加奶香味和營養，對柔軟度影響不大。"},
  {"id": 485, "keyword_tag": "90℃", "knowledge_tag": "溫度控制", "explanation": "餡餅為了皮薄柔軟不破，必須使用「全燙麵」。要讓麵粉裡的澱粉完全糊化，水溫至少必須達到將近沸騰的「90℃以上」。"},
  {"id": 486, "keyword_tag": "硬實", "knowledge_tag": "品質鑑定", "explanation": "叉燒包的特色就是麵皮像海綿蛋糕一樣極度鬆軟。如果蒸出來皮吃起來「硬實」像沒發的饅頭，那就是徹底失敗了。"},
  {"id": 487, "keyword_tag": "差", "knowledge_tag": "水質影響", "explanation": "如果煮麵水裡含有太多的鈣、鎂等礦物質（硬水），這些礦物質會讓麵條表面的蛋白質變質變硬，吃起來的口感就會變「差」。"},
  {"id": 488, "keyword_tag": "微生物檢驗", "knowledge_tag": "食品安全", "explanation": "細菌太小了，肉眼看不見，吃起來聞起來也不一定有味道。要知道麵條上的大腸桿菌或生菌數有沒有超標，唯一科學的方法就是送到實驗室做「微生物檢驗」。"},
  {"id": 489, "keyword_tag": "冰水", "knowledge_tag": "環境控制", "explanation": "夏天氣溫三十幾度，如果直接用常溫水打麵糰，機器摩擦生熱會讓麵糰溫度飆高、甚至開始發酸。所以夏天製麵必須加「冰水」來降溫。"},
  {"id": 490, "keyword_tag": "刀削麵", "knowledge_tag": "產品特性", "explanation": "刀削麵是典型的硬冷水麵，水分極少又充分揉壓出麵筋，削成厚厚的麵條煮熟後，具有非常強烈、有嚼勁的「韌性」。"},
  {"id": 491, "keyword_tag": "春捲", "knowledge_tag": "加工方式", "explanation": "水餃用煮的，豆沙包用蒸的，荷葉餅用烙的。只有包滿菜肉餡的「春捲（炸春捲）」，最適合丟進油鍋炸到金黃酥脆食用。"},
  {"id": 492, "keyword_tag": "蒸爐大小", "knowledge_tag": "製作技巧", "explanation": "饅頭組織要細緻，關鍵是發酵剛好、水分對、壓麵把空氣全擠掉。至於你家的「蒸爐大小」只影響一次能蒸幾顆，跟內部細不細緻完全無關。"},
  {"id": 493, "keyword_tag": "糖漿", "knowledge_tag": "產品異常分析", "explanation": "沙琪瑪炸好的短麵條，全靠熬煮到 115℃ 的「糖漿」冷卻後來把大家黏在一起。如果糖漿熬得不夠黏或裹得太少，切塊時就會整個鬆散掉。"},
  {"id": 494, "keyword_tag": "鹽", "knowledge_tag": "配方分析", "explanation": "老婆餅的糖餡軟硬度取決於糕仔粉吸水、糯米粉的Ｑ度、糖水的比例。加一小撮「鹽」只是為了提味不死甜，對軟硬度影響最小。"},
  {"id": 495, "keyword_tag": "豬油", "knowledge_tag": "原料特性", "explanation": "桃酥之所以能裂開漂亮的紋路，咬下去酥脆化口，最關鍵的靈魂原料就是使用了大量的傳統固態油脂——「豬油」。"},
  {"id": 496, "keyword_tag": "鹽", "knowledge_tag": "配方分析", "explanation": "叉燒包會膨脹裂開，是因為麵糊裡加了「碳酸氫銨（臭粉）」和「泡打粉」，加上大火蒸。配方裡通常不加鹽，鹽也跟裂開無關。"},
  {"id": 497, "keyword_tag": "柔軟", "knowledge_tag": "品質鑑定", "explanation": "龍鳳喜餅（傳統中式大餅）屬於糕皮類，烤出來經過幾天的回油後，外皮吃起來應該是香甜「柔軟」的，不能硬邦邦。"},
  {"id": 498, "keyword_tag": "緊實", "knowledge_tag": "品質鑑定", "explanation": "油條下鍋後會劇烈膨脹，裡面充滿大大小小的氣孔，吃起來酥脆。如果內部組織「緊實」沒有空洞，那就變成炸麵棍了，是失敗的。"},
  {"id": 499, "keyword_tag": "韌性強", "knowledge_tag": "麵糰特性", "explanation": "燙麵的麵筋被熱水燙死了，所以它的特性是柔軟、濕潤、好捏塑。吃起來Ｑ彈有咬勁的「韌性強」是冷水麵的專利，絕對不是燙麵的特性。"}
]

